mapper.insert:


		select seq_notice.nextval from dual


insert into notice(
	bo_no, bo_title, bo_content, bo_writer, bo_date
)values(
	#{boNo},#{boTitle},#{boContent},#{boWriter}, SYSDATE
)

mapper.update:
update 	notice
set		bo_hit 	= bo_hit + 1
where	bo_no 	= #{boNo}

mapper.select:
select b.*
from(	
	select a.* ,row_number() over (order by a.bo_no desc) rnum
	from (
			select
				bo_no, bo_title, bo_content, bo_writer, 
				to_char(bo_date, 'yy-mm-dd hh24:mi:ss') bo_date, bo_hit,
				(select count(file_no) from noticeFile nf where nf.bo_no=n.bo_no) as file_count
			from
				notice n
			where
				1=1

				order by bo_no desc
				) a
			) b

			where b.rnum >= #{startRow} and b.rnum <= #{endRow}
